import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
  server: {
    host: '0.0.0.0',  // 允许局域网访问
    port: 5173,
    strictPort: true,
  },
})

// 应用常量配置

/**
 * 动态获取API主机地址
 * 优先级: 环境变量 > 运行时自动检测 > 默认值
 * @returns {string} API主机地址
 */
const getDefaultHost = (): string => {
  // 优先级1: 环境变量显式配置
  if (import.meta.env.VITE_API_HOST) {
    return import.meta.env.VITE_API_HOST;
  }

  // 优先级2: 运行时自动检测浏览器访问的hostname
  if (typeof window !== 'undefined' && window.location) {
    return window.location.hostname;
  }

  // 优先级3: SSR场景或其他fallback
  return 'localhost';
};

/**
 * 动态获取API端口
 * @returns {number} API端口号
 */
const getDefaultPort = (): number => {
  const envPort = import.meta.env.VITE_API_PORT;
  return envPort ? parseInt(envPort) : 8001;
};

// 从环境变量读取端口配置,默认使用8001
const API_PORT = getDefaultPort();
const API_HOST = getDefaultHost();

export const config = {
  // API配置
  API_BASE_URL: import.meta.env.VITE_API_BASE_URL || `http://${API_HOST}:${API_PORT}`,
  WS_URL: import.meta.env.VITE_WS_URL || `ws://${API_HOST}:${API_PORT}`,
  API_PORT: API_PORT,
  API_HOST: API_HOST,

  // 应用配置
  APP_TITLE: import.meta.env.VITE_APP_TITLE || 'ROS远程监控系统',

  // WebSocket配置
  WS_RECONNECT_ATTEMPTS: 5,
  WS_RECONNECT_INTERVAL: 3000,

  // 数据配置
  MAX_HISTORY_POINTS: 1000,
  CHART_UPDATE_INTERVAL: 100,
  HEALTH_CHECK_INTERVAL: 5000,

  // UI配置
  SIDEBAR_WIDTH: 240,
  HEADER_HEIGHT: 64,
};

export const SENSOR_TOPICS = {
  IMU: 'imu',
  CAMERA: 'camera',
  LIDAR: 'lidar',
} as const;

export const CONNECTION_STATUS = {
  CONNECTED: 'connected',
  DISCONNECTED: 'disconnected',
  CONNECTING: 'connecting',
  ERROR: 'error',
} as const;

export const CHART_COLORS = {
  X_AXIS: '#ff4d4f',
  Y_AXIS: '#52c41a', 
  Z_AXIS: '#1890ff',
  W_AXIS: '#722ed1',
} as const;

// 机器人颜色映射（8 个预设颜色，为 SLAM 3D 多轨迹同屏用）
export const ROBOT_COLORS: readonly string[] = [
  '#00d2ff', // 青色
  '#ff6b6b', // 红色
  '#4caf50', // 绿色
  '#ffd700', // 金色
  '#a78bfa', // 紫色
  '#f97316', // 橙色
  '#fb7185', // 粉色
  '#38bdf8', // 蓝色
];

export function getRobotColor(index: number): string {
  return ROBOT_COLORS[index % ROBOT_COLORS.length];
}

import React, { useEffect } from 'react';

import { Header } from './Header';
import { Sidebar } from './Sidebar';
import { SystemStatus } from '../Dashboard/SystemStatus';
import { ConnectionStatus } from '../Dashboard/ConnectionStatus';
import { OverviewPanel } from '../Dashboard/OverviewPanel';
import CameraMonitor from '../CameraMonitor';
import DataCollectionControl from '../Sensors/DataCollectionControl';
import GNSSStatusPanel from '../Sensors/GNSSStatusPanel';
import SLAMMonitor from '../SLAM/SLAMMonitor';
import { useSystemStore } from '../../stores/useSystemStore';
import { apiService } from '../../services/api';
import { wsService } from '../../services/websocket';
import { config } from '../../utils/constants';

export const MainLayout: React.FC = () => {
  const { ui } = useSystemStore();
  const currentPage = ui.currentPage;

  // 初始化WebSocket连接
  useEffect(() => {
    const connectWebSocket = async () => {
      try {
        console.log('🔌 正在连接WebSocket...');
        await wsService.connect(config.API_HOST, config.API_PORT);
        console.log('✅ WebSocket全局连接成功');

        // 订阅所有传感器话题（多机模式下必须显式订阅才能接收广播数据）
        wsService.subscribe(['camera', 'lidar', 'gnss', 'imu', 'slam']);

        // 请求系统状态
        wsService.send({
          type: 'request_system_status',
          timestamp: new Date().toISOString(),
        });
      } catch (error) {
        console.error('❌ WebSocket连接失败:', error);
      }
    };

    connectWebSocket();

    return () => {
      console.log('🔌 断开WebSocket连接...');
      wsService.disconnect();
    };
  }, []);

  // 初始化API健康检查
  useEffect(() => {
    console.log('🚀 启动API健康检查...');

    // 开始定期健康检查（每10秒检查一次）
    apiService.startHealthCheck(10000);

    // 组件卸载时停止健康检查
    return () => {
      console.log('🛑 停止API健康检查...');
      apiService.stopHealthCheck();
    };
  }, []);

  const renderContent = () => {
    switch (currentPage) {
      case 'overview':
        return <OverviewPanel />;
      case 'dashboard':
        return <SystemStatus />;
      case 'camera':
        return <CameraMonitor />;
      case 'gnss':
        return <GNSSStatusPanel />;
      case 'slam':
        return <SLAMMonitor />;
      case 'connection':
        return <ConnectionStatus />;
      case 'data-collection':
        return <DataCollectionControl />;
      case 'settings':
        return (
          <div style={{ padding: '24px', textAlign: 'center' }}>
            <h2>系统设置</h2>
            <p>设置功能开发中...</p>
          </div>
        );
      default:
        return <SystemStatus />;
    }
  };

  return (
    <div style={{ 
      display: 'flex', 
      minHeight: '100vh',
      backgroundColor: '#f0f2f5'
    }}>
      {/* 侧边栏 */}
      <Sidebar />

      {/* 主内容区域 */}
      <div style={{ 
        flex: 1,
        display: 'flex',
        flexDirection: 'column',
        marginLeft: ui.sidebarCollapsed ? 80 : 240,
        transition: 'margin-left 0.2s ease',
        minWidth: 0, // 防止flex子元素溢出
      }}>
        {/* 顶部导航 */}
        <Header />

        {/* 主内容 */}
        <div style={{
          flex: 1,
          padding: '24px',
          marginTop: '64px', // Header高度
          overflow: 'auto',
          minHeight: 'calc(100vh - 64px)',
        }}>
          <div style={{
            background: '#fff',
            borderRadius: '8px',
            padding: '24px',
            boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
            minHeight: 'calc(100vh - 112px)', // 减去Header和padding
          }}>
            {renderContent()}
          </div>
        </div>
      </div>
    </div>
  );
};

