import { useState, useEffect, useRef, useCallback } from 'react';
import { config } from '../utils/constants';

interface WebSocketMessage {
  type: string;
  [key: string]: any;
}

interface UseWebSocketReturn {
  connected: boolean;
  error: string | null;
  sendMessage: (message: WebSocketMessage) => void;
  lastMessage: WebSocketMessage | null;
}

export const useWebSocket = (url: string = `${config.WS_URL}/ws`): UseWebSocketReturn => {
  const [connected, setConnected] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastMessage, setLastMessage] = useState<WebSocketMessage | null>(null);
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<number | null>(null);
  const reconnectAttempts = useRef(0);
  const maxReconnectAttempts = 5;
  const reconnectDelay = 3000;

  const connect = useCallback(() => {
    try {
      const clientId = `frontend_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      const wsUrl = `${url}/${clientId}`;
      
      const ws = new WebSocket(wsUrl);
      wsRef.current = ws;

      ws.onopen = () => {
        console.log('WebSocket connected');
        setConnected(true);
        setError(null);
        reconnectAttempts.current = 0;
      };

      ws.onmessage = (event) => {
        try {
          const message = JSON.parse(event.data);
          setLastMessage(message);
          
          // 处理不同类型的消息
          handleMessage(message);
          
          // 触发自定义事件，让组件能够接收到消息
          const customEvent = new CustomEvent('websocket-message', {
            detail: message
          });
          window.dispatchEvent(customEvent);
        } catch (error) {
          console.error('Failed to parse WebSocket message:', error);
        }
      };

      ws.onclose = () => {
        console.log('WebSocket disconnected');
        setConnected(false);
        attemptReconnect();
      };

      ws.onerror = (error) => {
        console.error('WebSocket error:', error);
        setError('WebSocket连接错误');
      };

    } catch (error) {
      console.error('Failed to create WebSocket:', error);
      setError('创建WebSocket连接失败');
    }
  }, [url]);

  const attemptReconnect = useCallback(() => {
    if (reconnectAttempts.current < maxReconnectAttempts) {
      reconnectAttempts.current++;
      console.log(`Attempting to reconnect... (${reconnectAttempts.current}/${maxReconnectAttempts})`);
      
      reconnectTimeoutRef.current = setTimeout(() => {
        connect();
      }, reconnectDelay);
    } else {
      setError('WebSocket重连失败，已达到最大重试次数');
    }
  }, [connect]);

  const disconnect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }
    
    setConnected(false);
  }, []);

  const sendMessage = useCallback((message: WebSocketMessage) => {
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(message));
    } else {
      console.error('WebSocket is not connected');
      setError('WebSocket未连接，无法发送消息');
    }
  }, []);

  const handleMessage = useCallback((message: WebSocketMessage) => {
    // 根据消息类型处理不同的逻辑
    switch (message.type) {
      case 'connected':
        console.log('WebSocket connection confirmed');
        break;
      case 'error':
        console.error('WebSocket error message:', message.message);
        setError(message.message);
        break;
      case 'subscription_confirmed':
        console.log('Topic subscription confirmed:', message.topics);
        break;
      case 'system_status':
        console.log('System status received:', message);
        break;
      default:
        // 其他消息类型可以在这里处理
        break;
    }
  }, []);

  useEffect(() => {
    connect();

    return () => {
      disconnect();
    };
  }, [connect, disconnect]);

  // 清理重连定时器
  useEffect(() => {
    return () => {
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
    };
  }, []);

  return {
    connected,
    error,
    sendMessage,
    lastMessage
  };
};

/**
 * 数据采集控制API服务
 * 最小化实现，遵循YAGNI和KISS原则
 */

import { config } from '../utils/constants';

export interface DataCollectionStatus {
  is_running: boolean;
  process_id: number | null;
  start_time: number | null;
  script_path: string;
  last_update: number;
}

export interface APIResponse<T = any> {
  success: boolean;
  message: string;
  data?: T;
}

class DataCollectionService {
  private baseURL: string;

  constructor(host: string = config.API_HOST, port: number = config.API_PORT) {
    this.baseURL = `http://${host}:${port}`;
  }

  /**
   * 启动数据采集
   */
  async startCollection(): Promise<APIResponse> {
    try {
      const response = await fetch(`${this.baseURL}/api/v1/data-collection/start`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          script: 'start_all.sh',
          timeout: 30
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      return {
        success: false,
        message: `启动失败: ${error instanceof Error ? error.message : '未知错误'}`
      };
    }
  }

  /**
   * 停止数据采集
   */
  async stopCollection(): Promise<APIResponse> {
    try {
      const response = await fetch(`${this.baseURL}/api/v1/data-collection/stop`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ force: false })
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      return {
        success: false,
        message: `停止失败: ${error instanceof Error ? error.message : '未知错误'}`
      };
    }
  }

  /**
   * 获取采集状态
   */
  async getStatus(): Promise<APIResponse<DataCollectionStatus>> {
    try {
      const response = await fetch(`${this.baseURL}/api/v1/data-collection/status`);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      return {
        success: false,
        message: `获取状态失败: ${error instanceof Error ? error.message : '未知错误'}`
      };
    }
  }
}

export const dataCollectionService = new DataCollectionService();

import { create } from 'zustand';
import type { ConnectionInfo } from '../types/api';

interface SystemStore {
  // 连接状态（全局 + 按机器人）
  connection: ConnectionInfo;
  robotConnections: Record<string, ConnectionInfo>;

  // 流量监控（按机器人）
  robotTraffic: Record<string, { total_kb: number; rate_kbps: number }>;

  // 性能指标
  performance: {
    wsLatency: number;
    dataRate: number;
    errorCount: number;
    uptime: number;
  };

  // UI 状态
  ui: {
    sidebarCollapsed: boolean;
    theme: 'light' | 'dark';
    currentPage: string;
  };

  // Actions — 全局连接
  updateConnectionStatus: (type: keyof ConnectionInfo, status: boolean) => void;
  updateLatency: (latency: number) => void;
  updatePerformanceMetrics: (metrics: Partial<SystemStore['performance']>) => void;

  // Actions — 按机器人连接
  updateRobotConnection: (robotId: string, type: keyof ConnectionInfo, status: boolean) => void;

  // Actions — 流量监控
  updateRobotTraffic: (traffic: Record<string, { total_kb: number; rate_kbps: number }>) => void;

  // UI Actions
  toggleSidebar: () => void;
  setCurrentPage: (page: string) => void;
  incrementErrorCount: () => void;
  resetErrorCount: () => void;
}

const defaultConnection: ConnectionInfo = {
  websocket: false,
  api: false,
  ros: false,
  latency: 0,
};

export const useSystemStore = create<SystemStore>((set) => ({
  connection: { ...defaultConnection },

  robotConnections: {},

  robotTraffic: {},

  performance: {
    wsLatency: 0,
    dataRate: 0,
    errorCount: 0,
    uptime: 0,
  },

  ui: {
    sidebarCollapsed: false,
    theme: 'dark',
    currentPage: 'dashboard',
  },

  // 全局连接（浏览器 WS + API 状态）
  updateConnectionStatus: (type: keyof ConnectionInfo, status: boolean) => set((state) => ({
    connection: { ...state.connection, [type]: status },
  })),

  updateLatency: (latency: number) => set((state) => ({
    connection: { ...state.connection, latency },
    performance: { ...state.performance, wsLatency: latency },
  })),

  updatePerformanceMetrics: (metrics: Partial<SystemStore['performance']>) => set((state) => ({
    performance: { ...state.performance, ...metrics },
  })),

  // 按机器人连接状态
  updateRobotConnection: (robotId: string, type: keyof ConnectionInfo, status: boolean) => set((state) => {
    const current = state.robotConnections[robotId] || { ...defaultConnection };
    return {
      robotConnections: {
        ...state.robotConnections,
        [robotId]: { ...current, [type]: status },
      },
    };
  }),

  updateRobotTraffic: (traffic) => set({ robotTraffic: traffic }),

  toggleSidebar: () => set((state) => ({
    ui: { ...state.ui, sidebarCollapsed: !state.ui.sidebarCollapsed },
  })),

  setCurrentPage: (page: string) => set((state) => ({
    ui: { ...state.ui, currentPage: page },
  })),

  incrementErrorCount: () => set((state) => ({
    performance: { ...state.performance, errorCount: state.performance.errorCount + 1 },
  })),

  resetErrorCount: () => set((state) => ({
    performance: { ...state.performance, errorCount: 0 },
  })),
}));

