// API接口类型定义

export interface ApiResponse<T = any> {
  success: boolean;
  message: string;
  data?: T;
  error?: string;
  timestamp?: string;
}

export interface HealthResponse {
  success: boolean;
  message: string;
  ros_ready: boolean;
}

export interface SystemStatus {
  ros_master: {
    connected: boolean;
    uri: string;
    topics: number;
    nodes: number;
  };
  sensors: {
    camera: SensorStatus;
    lidar: SensorStatus;
    imu: SensorStatus;
  };
  resources: {
    cpu_usage: number;
    memory_usage: number;
    disk_usage: number;
  };
  uptime: number;
}

export interface SensorStatus {
  active: boolean;
  frequency: number;
  last_message: string;
  error_count: number;
}

export interface ConnectionInfo {
  websocket: boolean;
  api: boolean;
  ros: boolean;
  latency: number;
}

/**
 * GNSS/RTK数据类型定义
 */

/**
 * GPS时间信息
 */
export interface GNSSTime {
  week: number;      // GPS周数
  tow: number;       // 周内秒(Time of Week)
}

/**
 * GNSS位置信息
 */
export interface GNSSPosition {
  latitude: number;   // 纬度(度)
  longitude: number;  // 经度(度)
  altitude: number;   // 椭球高(米)
  height_msl: number; // 海拔高度(米, Mean Sea Level)
}

/**
 * GNSS精度信息
 */
export interface GNSSAccuracy {
  h_acc: number;  // 水平精度(米)
  v_acc: number;  // 垂直精度(米)
  p_dop: number;  // 位置精度因子(Position Dilution of Precision)
}

/**
 * GNSS速度信息
 */
export interface GNSSVelocity {
  vel_n: number;   // 北向速度(m/s)
  vel_e: number;   // 东向速度(m/s)
  vel_d: number;   // 下向速度(m/s)
  vel_acc: number; // 速度精度(m/s)
}

/**
 * GNSS定位质量信息
 */
export interface GNSSQuality {
  fix_type: number;      // 定位类型: 0=无定位, 1=单点, 2=2D, 3=3D
  valid_fix: boolean;    // 定位有效性
  diff_soln: boolean;    // 是否应用差分改正
  carr_soln: number;     // 载波解状态: 0=无, 1=浮点解, 2=固定解
  num_sv: number;        // 使用的卫星数量
}

/**
 * RTK定位状态类型
 */
export type RTKStatus = 
  | 'RTK_FIXED'  // ✅ RTK固定解(最高精度)
  | 'RTK_FLOAT'  // ⚠️ RTK浮点解(中等精度)
  | 'GPS_3D'     // 📡 3D定位(普通GPS)
  | 'GPS_2D'     // 📡 2D定位
  | 'GPS_1D'     // 单点定位
  | 'NO_FIX';    // ❌ 无定位

/**
 * GNSS完整数据结构
 */
export interface GNSSData {
  rtk_status: RTKStatus;       // RTK状态
  quality: GNSSQuality;        // 定位质量
  position: GNSSPosition;      // 位置信息
  accuracy: GNSSAccuracy;      // 精度信息
  velocity: GNSSVelocity;      // 速度信息
  time: GNSSTime;              // GPS时间
  timestamp: number;           // Unix时间戳
  sequence: number;            // 帧序号
}

// 传感器数据类型定义

export interface CameraData {
  camera_id: string;
  timestamp: number;
  sequence: number;
  encoding: string;
  width: number;
  height: number;
  data: string; // Base64编码的图像数据
  compressed: boolean;
}

export interface LidarData {
  timestamp: number;
  frame_id: string;
  point_count: number;
  points: number[]; // 点云数据数组
}

export interface SensorStatus {
  connected: boolean;
  lastUpdate: number;
  frequency: number;
  errorCount: number;
}

// SLAM相关数据类型
export interface Pose {
  position: {
    x: number;
    y: number;
    z: number;
  };
  orientation: {
    x: number;
    y: number;
    z: number;
    w: number;
  };
}

export interface PathData {
  topic: string;
  timestamp: number;
  frame_id: string;
  sequence: number;
  total_poses: number;
  sampled_poses: number;
  poses: Pose[];
}

export interface OdometryData {
  topic: string;
  timestamp: number;
  frame_id: string;
  child_frame_id: string;
  sequence: number;
  pose: Pose;
  twist: {
    linear: { x: number; y: number; z: number };
    angular: { x: number; y: number; z: number };
  };
}

export interface RegisteredCloudData {
  topic: string;
  timestamp: number;
  frame_id: string;
  sequence: number;
  total_points: number;
  sampled_points: number;
  points: number[][]; // [[x,y,z], [x,y,z], ...]
  colors?: number[][]; // [[r,g,b], [r,g,b], ...] 0-255
  has_rgb?: boolean;
  fields: string[];
}

export interface SLAMData {
  path: PathData | null;
  odometry: OdometryData | null;
  registeredCloud: RegisteredCloudData | null;
  status: SensorStatus;
}

// WebSocket消息类型定义

export interface WSMessage {
  type: string;
  timestamp: string;
  data: any;
}

export interface WSSubscribeMessage extends WSMessage {
  type: 'subscribe';
  data: {
    topics: string[];
    frequency?: number;
  };
}

export interface WSUnsubscribeMessage extends WSMessage {
  type: 'unsubscribe';
  data: {
    topics: string[];
  };
}

export interface WSConnectedMessage extends WSMessage {
  type: 'connected';
  client_id: string;
}

export interface WSSubscribedMessage extends WSMessage {
  type: 'subscribed';
  topics: string[];
}

export interface WSIMUMessage extends WSMessage {
  type: 'imu';
  data: {
    timestamp: number;
    data: {
      timestamp: number;
      orientation: {
        x: number; y: number; z: number; w: number;
      };
      angular_velocity: {
        x: number; y: number; z: number;
      };
      linear_acceleration: {
        x: number; y: number; z: number;
      };
    };
  };
}

export interface WSCameraMessage extends WSMessage {
  type: 'camera';
  data: {
    timestamp: number;
    data: {
      camera_id: string;
      timestamp: number;
      sequence: number;
      encoding: string;
      width: number;
      height: number;
      data: string;
      compressed: boolean;
    };
  };
}

export interface WSErrorMessage extends WSMessage {
  type: 'error';
  data: {
    message: string;
    code?: number;
  };
}

